import React from 'react';

const Product = ({ cake, onOpenDetail }) => {
  return (
    <div className="card" style={{ cursor: 'pointer' }} onClick={() => onOpenDetail(cake)}>
      {/* Container bao quanh ảnh để hiển thị viền kim tuyến từ App.css */}
      <div className="img-container">
        <img src={cake.img} alt={cake.name} />
      </div>
      
      <h3>{cake.name}</h3>
      <p>{cake.price}</p>
      
      <button onClick={(e) => { 
        e.stopPropagation(); 
        alert(`Đã thêm ${cake.name} vào giỏ hàng!`); 
      }}>
        Mua ngay
      </button>
      
      <div style={{ fontSize: '0.8rem', color: '#666', marginTop: '10px' }}>
        Nhấn để xem chi tiết
      </div>
    </div>
  );
};

export default Product;
